_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //MilkDrop3 Zoom Mode:
vUv = 0.25 + 0.5*vUv;

uv10 = (vUv-.5)*uAspect.xy;
float ang1 = matan2 (uv10.x,uv10.y)/M_PI;
float ang2 = 0.5 + (1.0 - abs( fract(ang1 * 0.5) * 2 - 1.0 )-.5);
float z = 0.02;
uv1 = vec2 (.6+3*z-z/length(uv10), ang2).yx;
ret1= ret2= 0;
dz= dz1=0;
uv3 = uv1;
float mask = clamp01(4*uv3.y) * clamp01(vRadius*1);
uv3 = fract(uv3);
dz0.x = (lum(GP(uv3+hor))- lum(GP(uv3-hor)));
dz0.y = (lum(GP(uv3+ver))- lum(GP(uv3-ver)));
dz0.x += 2*(lum(GB(uv3+hor))- lum(GB(uv3-hor)));
dz0.y += 2*(lum(GB(uv3+ver))- lum(GB(uv3-ver)));
dz +=  mask*dz0/2;
ret1 = max(ret1,(GP(uv3)+GB(uv3))/2*mask);
ret2 = abs(GetPixel(uv3)-GetBlur1(uv3));

mus = 1.2/length(sin(12*(uv1+dz/2 + 2.25*(ret1-0.5)) +uTime))*vRadius*(1-vRadius);

float stars = 0;
int anz = 6;
uv2 = vec2 (0.02/length(uv10), ang2).yx;
for (int n=1; n <= anz; n++)
{
  vec2 uv4 = 8.0*((1.0+n)*(uv2+(dz+(ret1-.5)) + 0.1*n )+ vec2(0,uTime*.1));
  float smask = clamp01(texture(sampler_pw_noise_lq,uv4/256)-.95);
  stars = max(stars,(0.1/pow(length(fract(uv4)-.5),2)*smask));
n++;
}

//mus = max(mus,stars);
uv2 = vec2 (22*length(uv10), ang2).yx;
uv2 = uv2*.2+vec2(0.07*uTime,.5);
uv2=fract(uv2);
vec3 bk = GetBlur2(uv2) * 2*(1-vRadius) + .2;
ret = sqrt(ret1)*(1+ret2)*(.25+mus) ;
ret *= 1+6*length(dz);
ret += clamp01(stars)*.7;
ret += 2*bk* clamp01(1-lum(ret1)*16)*sqrt(audioMidSmooth+1)*clamp01(0.035/(0.001+sqrt(length(uv10))));

ret *= 3.7-vRadius;
ret -= 0.3;
//ret = GetPixel(vUv);
//MilkDrop3 Color Mode:
ret /= vec3(2.7,2.1,2.0);
//MilkDrop3 Red Dot:
ret /= vec3(vRadius*3,1,1);

  fragColor = ret;
}
